import React from 'react';

const products = [
  { id: 1, name: 'Shirt', price: 25 },
  { id: 2, name: 'Shoes', price: 60 },
  { id: 3, name: 'Bag', price: 40 }
];

export default function Products() {
  return (
    <div>
      {products.map(product => (
        <div key={product.id}>
          <h3>{product.name}</h3>
          <p>${product.price}</p>
        </div>
      ))}
    </div>
  );
}
